use soroban_sdk::{contract, contractimpl, Address, Env, Bytes};

#[contractimpl]
impl UpgradableContract {
    // VULNERABLE: upgrade without auth guard
    pub fn upgrade(env: Env, new_wasm: Bytes) {
        env.deployer().upload_contract_wasm(&new_wasm);
    }

    // VULNERABLE: update_contract without auth guard
    pub fn update_contract(env: Env, new_wasm: Bytes) {
        env.deployer().upload_contract_wasm(&new_wasm);
    }

    // VULNERABLE: set_wasm without auth guard
    pub fn set_wasm(env: Env, code: Bytes) {
        env.deployer().upload_contract_wasm(&code);
    }

    // SAFE: regular function (no upgrade patterns, not flagged)
    pub fn get_version(env: Env) -> u32 {
        1
    }
}
